// Input is now the merged stream: item 0 = ISO reference, items 1-7 = evidence
const allItems = $input.all();

// Item 0 is the ISO reference
const isoFileName = allItems[0].binary.isoData.fileName;
const isoBuffer = await this.helpers.getBinaryDataBuffer(0, 'isoData');
const isoText = isoBuffer.toString('utf-8');

// Items 1 onwards are the evidence files
let evidenceText = '';
for (let i = 1; i < allItems.length; i++) {
  const fileName = allItems[i].binary.data.fileName;
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const content = buffer.toString('utf-8');
  evidenceText += `\n\n=== FILENAME: ${fileName} ===\n${content}`;
}

// Combine into one structured block
const combined = `ISO 27002 REFERENCE DOCUMENT (FILENAME: ${isoFileName}):\n${isoText}\n\n\n--- COMPANY EVIDENCE DOCUMENTS ---${evidenceText}`;

// Output a single item
return [{ json: { combinedDocuments: combined } }];
